import{_ as a,o as t,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Enable App Aggregated Event Measurement Support","description":"","frontmatter":{"title":"Enable App Aggregated Event Measurement Support","slug":"enable-app-aggregated-event-measurement-support"},"headers":[],"relativePath":"marketer-hub/enable-app-aggregated-event-measurement-support.md","filePath":"marketer-hub/enable-app-aggregated-event-measurement-support.md"}'),n={name:"marketer-hub/enable-app-aggregated-event-measurement-support.md"};function o(s,e,l,d,p,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>With iOS 14.5 and later, Apple&#39;s App Tracking Transparency (ATT) framework requires apps to request user permission before accessing the Identifier for Advertisers (IDFA). When users decline tracking permission (which is often the case), traditional attribution methods become limited. To address this challenge, Meta introduced <strong>Aggregated Event Measurement (AEM)</strong>.</p><p>Meta&#39;s AEM is a privacy-preserving protocol that allows measurement of web and app events from iOS 14.5+ devices, <em>even when users have opted out of tracking</em>. AEM enables you to:</p><ul><li>Measure app installs and re-engagement campaigns on Meta properties.</li><li>Optimize campaigns using conversion events without requiring IDFA.</li><li>Access near real-time reporting for faster campaign optimization.</li><li>Attribute events while respecting user privacy preferences.</li></ul><h3 id="aem-and-skan" tabindex="-1">AEM and SKAN <a class="header-anchor" href="#aem-and-skan" aria-label="Permalink to &quot;AEM and SKAN&quot;">​</a></h3><p>AEM works alongside Apple&#39;s SKAdNetwork (SKAN) but serves a different purpose. While SKAN provides aggregated, delayed attribution data through Apple&#39;s framework, AEM offers:</p><ul><li>Faster reporting.</li><li>Campaign-level attribution data from Meta.</li><li>Compatibility with Meta&#39;s campaign optimization systems.</li><li>You can run both AEM and SKAN simultaneously for the same campaign, giving you more complete measurement across different attribution frameworks.</li></ul><h3 id="campaign-support" tabindex="-1">Campaign support <a class="header-anchor" href="#campaign-support" aria-label="Permalink to &quot;Campaign support&quot;">​</a></h3><p>AEM supports two kinds of Meta campaigns:</p><table tabindex="0"><thead><tr><th>Campaign Type</th><th>Description</th></tr></thead><tbody><tr><td>Mobile App Engagement (MAE)</td><td>AEM is available for the following campaign types when the destination is set to a mobile app: - Sales campaigns, with catalog turned on or off - Lead campaigns - Engagement campaigns <strong>Note</strong>: MAE campaigns require deep linking configuration (<a href="https://help.branch.io/developers-hub/docs/ios-universal-links" target="_blank" rel="noreferrer">iOS Universal Links</a> or <a href="https://help.branch.io/docs/advanced-link-configuration" target="_blank" rel="noreferrer">URI schemes</a>).</td></tr><tr><td>Mobile App Install (MAI)</td><td>AEM includes campaigns that use the app promotion objective. This means you can now run app promotion campaigns without configuring app events for SKAN, and more app events will be available for ad delivery optimization. You can continue to configure events for SKAN if you want to view performance across platforms. Attribution for mobile app installs is also supported. <strong>Note</strong>: MAI campaigns work automatically once AEM is enabled.</td></tr></tbody></table><h3 id="how-aem-works" tabindex="-1">How AEM works <a class="header-anchor" href="#how-aem-works" aria-label="Permalink to &quot;How AEM works&quot;">​</a></h3><p>Instead of using device-level identifiers like IDFA, AEM utilizes aggregate identifiers:</p><table tabindex="0"><thead><tr><th>Identifier</th><th>Description</th></tr></thead><tbody><tr><td><code>campaign_ids</code></td><td>A set of IDs found on some links that open the app from Facebook ads persisted for 7 days and forwarded to Facebook for campaign optimization. <strong>Required</strong> for <a href="./enable-app-aggregated-event-measurement-support.html#campaign-support">MAE</a> campaigns.</td></tr><tr><td><code>anon_id</code></td><td>An ID generated automatically by the Branch SDK, persisted on install and forwarded to Facebook for campaign optimization. Available for <a href="https://github.com/BranchMetrics/ios-branch-deep-linking-attribution/releases/tag/2.1.2" target="_blank" rel="noreferrer">SDK v2.1.2</a>+. <strong>Optional</strong> for <a href="./enable-app-aggregated-event-measurement-support.html#campaign-support">MAE</a> campaigns.</td></tr></tbody></table><p>These identifiers are forwarded to Facebook through all conversion events for re-engagement campaign optimization.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before enabling AEM, make sure you meet the requirements in this section.</p><h3 id="branch-requirements" tabindex="-1">Branch requirements <a class="header-anchor" href="#branch-requirements" aria-label="Permalink to &quot;Branch requirements&quot;">​</a></h3><ol><li><p>Create a <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">Branch</a> account.</p></li><li><p>Enable Branch Ads for your Branch account. Please contact your Account Manager or <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">our Sales team</a> to learn more about pricing and availability.</p></li><li><p>Implement the Branch iOS SDK into your mobile app.</p><ol><li>Minimum version: <a href="https://github.com/BranchMetrics/ios-branch-deep-linking-attribution/releases/tag/2.1.2" target="_blank" rel="noreferrer">SDK v2.1.2</a></li><li>Recommended version: <a href="https://github.com/BranchMetrics/ios-branch-deep-linking-attribution/releases" target="_blank" rel="noreferrer">latest</a></li></ol></li><li><p><a href="./ad-partner-integration-guide.html">Enable the Facebook integration</a> in Branch.</p></li></ol><h3 id="meta-requirements" tabindex="-1">Meta requirements <a class="header-anchor" href="#meta-requirements" aria-label="Permalink to &quot;Meta requirements&quot;">​</a></h3><ol><li>Obtain admin access to your Meta Business Manager account.</li><li>Register your app with Meta Business Manager. Meta determines app eligibility for AEM. If your app is eligible, AEM will appear as the default attribution option when you create campaigns in Meta Ads Manager.</li></ol><h3 id="technical-requirements" tabindex="-1">Technical requirements <a class="header-anchor" href="#technical-requirements" aria-label="Permalink to &quot;Technical requirements&quot;">​</a></h3><p>The technical requirements for AEM depend on your <a href="./enable-app-aggregated-event-measurement-support.html#campaign-support">campaign type</a>.</p><p><strong>For all AEM campaigns (MAI and MAE)</strong>:</p><ul><li>Ensure your event postbacks in Branch are <a href="./enable-app-aggregated-event-measurement-support.html#configure-events">configured to send events</a> to Meta.</li></ul><p><strong>For MAE campaigns</strong>:</p><ul><li>Your app must support <a href="https://help.branch.io/developers-hub/docs/ios-universal-links" target="_blank" rel="noreferrer">iOS Universal Links</a> or <a href="https://help.branch.io/docs/advanced-link-configuration" target="_blank" rel="noreferrer">URI schemes</a>.</li><li>Your app must properly handle <a href="./deep-link-reference.html">deep links</a> in Meta campaigns.</li></ul><p><strong>For MAI campaigns</strong>:</p><ul><li>MAI campaigns work automatically once AEM is enabled. No additional deep linking configuration is required.</li></ul><h3 id="configure-events" tabindex="-1">Configure events <a class="header-anchor" href="#configure-events" aria-label="Permalink to &quot;Configure events&quot;">​</a></h3><p>Before enabling AEM, configure which Branch events are sent to Meta for campaign optimization. Event mapping tells Meta which user actions to optimize your campaigns for, such as purchases, registrations, or content views.</p><h4 id="available-standard-meta-events" tabindex="-1">Available standard Meta events <a class="header-anchor" href="#available-standard-meta-events" aria-label="Permalink to &quot;Available standard Meta events&quot;">​</a></h4><p>Branch maps your events to Meta&#39;s standard event names for optimization. Common Meta events include:</p><table tabindex="0"><thead><tr><th><strong>Meta event name</strong></th><th>Branch event name</th></tr></thead><tbody><tr><td><code>MOBILE_APP_INSTALL</code></td><td><code>INSTALL</code></td></tr><tr><td><code>fb_mobile_activate_app</code></td><td><code>OPEN</code></td></tr><tr><td><code>fb_mobile_add_payment_info</code></td><td><code>ADD_PAYMENT_INFO</code></td></tr><tr><td><code>fb_mobile_add_to_cart</code></td><td><code>ADD_TO_CART</code></td></tr><tr><td><code>fb_mobile_add_to_wishlist</code></td><td><code>ADD_TO_WISHLIST</code></td></tr><tr><td><code>fb_mobile_complete_registration</code></td><td><code>COMPLETE_REGISTRATION</code></td></tr><tr><td><code>fb_mobile_content_view</code></td><td><code>VIEW_ITEM</code></td></tr><tr><td><code>fb_mobile_initiated_checkout</code></td><td><code>INITIATE_PURCHASE</code></td></tr><tr><td><code>fb_mobile_level_achieved</code></td><td><code>ACHIEVE_LEVEL</code></td></tr><tr><td><code>fb_mobile_purchase</code></td><td><code>PURCHASE</code></td></tr><tr><td><code>fb_mobile_rate</code></td><td><code>RATE</code></td></tr><tr><td><code>fb_mobile_search</code></td><td><code>SEARCH</code></td></tr><tr><td><code>fb_mobile_spent_credits</code></td><td><code>SPEND_CREDITS</code></td></tr><tr><td><code>fb_mobile_tutorial_completion</code></td><td><code>COMPLETE_TUTORIAL</code></td></tr></tbody></table><p>For a complete list of Meta events and their parameters, see the <a href="./facebook-ads-overview.html#event-names">Facebook Ads Overview article</a>.</p><h4 id="set-event-mappings" tabindex="-1">Set event mappings <a class="header-anchor" href="#set-event-mappings" aria-label="Permalink to &quot;Set event mappings&quot;">​</a></h4><p>In the <a href="https://dashboard.branch.io/ads/partner-management/a_facebook?tab=event_config" target="_blank" rel="noreferrer"><strong>Events Config tab</strong></a>, you&#39;ll see a mapping table with three columns:</p><ul><li><strong>Your Event Name</strong>: The Branch events tracked in your app (INSTALL, OPEN, PURCHASE, etc.)</li><li><strong>Your Customer Event Alias</strong>: Optional custom names for organizing events internally. Most users can leave this set to &quot;All Aliases.&quot;</li><li><strong>Ad Partner Event Name</strong>: Meta&#39;s standard names. These are the events Meta recognizes and can optimize campaigns for.</li></ul><p>To set event mappings in Branch:</p><ol><li><p>In Branch, navigate to <strong>Configure → Ads Partners →</strong> <a href="https://dashboard.branch.io/ads/partner-management/a_facebook?tab=event_config" target="_blank" rel="noreferrer"><strong>Events Config</strong></a>.</p></li><li><p>Review the default event mappings Branch has configured.</p></li><li><p>To add additional events:</p><ol><li>Select the <strong>Add Events Mapping</strong> button.</li><li>Select your Branch event from the <strong>Your Event Name</strong> column.</li><li>Choose the corresponding Meta event from the <strong>Ad Partner Event Name</strong> column.</li><li>Make sure the <strong>Enabled</strong> checkbox is checked so the event is active.</li></ol></li><li><p>To modify existing mappings:</p><ol><li>Use the dropdowns to select different Meta event names.</li><li>Click the <strong>trash icon</strong> to remove unwanted mappings.</li></ol></li><li><p>Select <strong>Save</strong> to apply your changes.</p></li></ol><h4 id="verify-event-mappings" tabindex="-1">Verify event mappings <a class="header-anchor" href="#verify-event-mappings" aria-label="Permalink to &quot;Verify event mappings&quot;">​</a></h4><p>It’s important to verify that your events are being sent to Meta and they’re properly configured.</p><p><strong>In your app</strong>:</p><ul><li>Trigger a test event (e.g., make a test purchase).</li><li>Check Branch <a href="https://dashboard.branch.io/overview/events" target="_blank" rel="noreferrer">Liveview</a> to confirm the event appears.</li><li>Verify the event includes any required parameters (like revenue for purchases).</li></ul><p><strong>In Meta Events Manager</strong>:</p><ul><li>Log in to Meta Business Manager.</li><li>Go to Events Manager and select your app.</li><li>Check the Activity tab to see if your mapped events are being received.</li><li>Look for any errors or warnings about event eligibility.</li></ul><p><strong>In Meta Ads Manager</strong>:</p><p>When creating a campaign, your mapped events should appear as available optimization events. If an event doesn&#39;t appear, it may not be eligible for AEM.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Event data typically appears within minutes to hours after configuration, but allow up to 24 hours for full propagation through Meta&#39;s systems.</p></div><h2 id="enable-aem" tabindex="-1">Enable AEM <a class="header-anchor" href="#enable-aem" aria-label="Permalink to &quot;Enable AEM&quot;">​</a></h2><ol><li><p>Contact your Account Manager from Meta to enable AEM support for your account. <strong>Meta must enable AEM on their side before you can activate it in Branch</strong>.</p></li><li><p>(Optional) To improve event eligibility and AEM performance, configure Meta to use MMP (Mobile Measurement Partner) as your preferred connection method:</p><ol><li>Go to Meta Events Manager and select your app.</li><li>Set “MMP” as your preferred connection method.</li><li>Ensure install and post-install events use the same connection method.</li><li>Learn more in Meta’s <a href="https://www.facebook.com/business/help/3215014965459549" target="_blank" rel="noreferrer">documentation</a>.</li></ol></li><li><p>In the Branch Dashboard, under <strong>Ads</strong> → <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a>, search for Facebook.</p></li><li><p>Navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_facebook?tab=events" target="_blank" rel="noreferrer"><strong>Events Config tab</strong></a>, and toggle the <strong>Enable Aggregated Event Measurement (AEM)</strong> switch below your event mappings.</p></li></ol><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>You must re-toggle the AEM switch in Branch if the MAI supported SDK version is updated or if AEM was enabled before MAI readiness release.</p></div><h2 id="optional-set-custom-id" tabindex="-1">(Optional) Set custom ID <a class="header-anchor" href="#optional-set-custom-id" aria-label="Permalink to &quot;(Optional) Set custom ID&quot;">​</a></h2><p>Branch automatically creates and sets a GUID for the <code>anon_id</code> field and sends that to Facebook. <strong>Most users do not need to modify this setting.</strong></p><p>You may want to set a custom <code>anon_id</code> if you:</p><ul><li>Have an existing user identification system you want to align with across platforms.</li><li>Need to maintain consistent IDs across multiple attribution providers.</li><li>Have specific user privacy or identifier requirements unique to your app.</li></ul><p>If you determine you need a custom ID, use the <code>setAnonID</code> method:</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-e03SK" id="tab-FrNbXM3" checked><label data-title="Swift" for="tab-FrNbXM3">Swift</label><input type="radio" name="group-e03SK" id="tab-Jb9K2zE"><label data-title="Objective-C" for="tab-Jb9K2zE">Objective-C</label></div><div class="blocks"><div class="language-swift vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">swift</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Branch.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">setAnonID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-custom-anon-id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><div class="language-objectivec vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">objectivec</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Branch setAnonID:@&quot;your-custom-anon-id&quot;];</span></span></code></pre></div></div></div><h2 id="understand-aem-data" tabindex="-1">Understand AEM data <a class="header-anchor" href="#understand-aem-data" aria-label="Permalink to &quot;Understand AEM data&quot;">​</a></h2><p>AEM provides the following campaign-level data in Branch:</p><ul><li><code>campaign_id</code> - Meta campaign identifier</li><li><code>ad_id</code> - Ad identifier</li><li><code>creative_id</code> - Creative identifier</li><li><code>secondary_publisher</code> - Placement (Instagram, Facebook, Audience Network, etc.)</li><li><code>ad_set_id</code> - Ad set identifier</li></ul><h4 id="data-limitations" tabindex="-1">Data limitations <a class="header-anchor" href="#data-limitations" aria-label="Permalink to &quot;Data limitations&quot;">​</a></h4><p>Due to Meta&#39;s privacy-preserving approach, the <code>campaign_name</code> field will show as <code>Unpopulated</code> in Branch reports and exports. This is a Meta limitation that affects all mobile measurement partners using AEM.</p><p><strong>Please use</strong> <code>campaign_id</code> <strong>to identify campaigns instead</strong>.</p><h3 id="aem-data-in-branch" tabindex="-1">AEM data in Branch <a class="header-anchor" href="#aem-data-in-branch" aria-label="Permalink to &quot;AEM data in Branch&quot;">​</a></h3><p><strong>Dashboard reporting:</strong></p><ul><li>AEM-attributed events appear in your standard Branch analytics reporting.</li><li>Branch includes AEM campaigns in last-touch attribution results.</li><li>Filter and segment your data using Branch’s <a href="./enable-app-aggregated-event-measurement-support.html#understand-aem-data">available AEM fields</a>.</li></ul><p><strong>Exports and webhooks:</strong></p><ul><li>Log-level data exports include all AEM-attributed events.</li><li>Events attributed to Facebook AEM campaigns display full available attribution data.</li><li>Access detailed event-level data through Branch&#39;s <a href="./data-feeds-overview.html">data export options</a>.</li></ul><p><strong>Data freshness:</strong></p><ul><li>Near real-time reporting (events appear within minutes to hours).</li><li>Significantly faster than SKAdNetwork&#39;s 24-72 hour reporting delay.</li><li>Most recent campaign performance data available for quick optimization decisions.</li></ul><p>For more on Branch&#39;s iOS attribution approach, see <a href="./ios-attribution-best-practices.html">iOS Attribution Best Practices</a>.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>If an advertiser also uses the Facebook SDK for iOS, what should they do to enable App AEM?</summary><p>If an advertiser uses both the Branch SDK and the Facebook SDK for iOS, they can pass the events in their app campaigns through either method. As a best practice ensure that the install and post-install events use the same preferred connection method by following <a href="https://www.facebook.com/business/help/3215014965459549" target="_blank" rel="noreferrer">these steps from Facebook</a>.</p></details><details><summary>How is Branch integrating App AEM campaigns into reporting or exports?</summary><p>Branch takes App AEM Campaigns into consideration for last touch attribution results.</p><p>Log-level data exports for all events is displayed in Exports/Webhooks for events attributed to Facebook AEM campaigns.</p></details><details><summary>What does AEM reporting look like?</summary><p>Meta does not provide <code>campaign_group_name</code> for AEM, which Branch maps to Campaign Name on the dashboard and exports. So <code>campaign_name</code> for events attributed via Meta AEM protocol will be marked as <code>Unpopulated</code>.</p><p>Data available under AEM is as follows:<code>campaign_id</code>, <code>ad_id</code>. <code>creative_id</code>, <code>secondary_publisher</code>, <code>ad_set_id</code>.</p></details><details><summary>Why does my event data say &quot;Ineligible&quot;?</summary><p>You may run into this issue if you toggled AEM on in the Branch Dashboard before setting up AEM in Meta. You need to set up AEM in Meta first, then enable it in the Branch Dashboard.</p><p>If you&#39;ve already run into this issue, you can resolve it by toggling AEM off and back on again in the Branch Dashboard.</p></details><details><summary>How long until I see AEM data after enabling?</summary><p><strong>Event mapping changes</strong>: Within minutes to hours for events to start flowing. Allow up to 24 hours for full propagation through Meta&#39;s systems.<br><strong>After enabling AEM</strong>: New events should appear once campaigns are running.<br><strong>First campaign data</strong>: Allow 24-48 hours after launching your first AEM campaign to see meaningful data.<br><strong>After toggling AEM off/on</strong>: If you need to retoggle the AEM switch, allow a few hours for data flow to resume.</p></details><details><summary>Why aren’t my Mobile App Engagement (MAE) campaigns getting attributed?</summary><p>For MAE re-engagement campaigns specifically, attribution requires proper deep linking configuration.</p><p><strong>Check the following</strong>:</p><ul><li>Verify <a href="https://help.branch.io/developers-hub/docs/ios-universal-links" target="_blank" rel="noreferrer">iOS Universal Links</a> or <a href="./advanced-link-configuration.html">URI Schemes</a> are properly configured.</li><li>Test that your app opens properly when a <a href="./ad-links.html">Branch Ad Link</a> is clicked from Meta ads.</li><li>Confirm the <code>campaign_ids</code> field is being passed through the Branch Ad Link.</li><li>Check that <a href="./deep-link-reference.html">deep link handling</a> is implemented correctly in your app.</li><li>Ensure you completed the deep linking requirements in the “<a href="./enable-app-aggregated-event-measurement-support.html#technical-requirements">Technical Requirements</a>” section.</li><li>In Meta, verify MAE campaigns are set to open your app (not web).</li></ul><p><strong>To test deep linking</strong>:</p><ol><li>Create a test MAE campaign in Meta that includes a Branch Ad Link.</li><li>Click the ad from a test device.</li><li>Verify the app opens and doesn’t redirect to web.</li><li>Check Branch <a href="https://dashboard.branch.io/overview/events" target="_blank" rel="noreferrer">Liveview</a> to see if the deep link data is received.</li></ol></details>',78)])])}const g=a(n,[["render",o]]);export{u as __pageData,g as default};
